import{c as o,Q as p,j as t,m as d}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"003-boot-long-mode-3 · Long Mode","description":"","frontmatter":{"title":"003-boot-long-mode-3 · Long Mode"},"headers":[],"relativePath":"hands-on/003-boot-long-mode-3.md","filePath":"hands-on/003-boot-long-mode-3.md","lastUpdated":1779686691000}'),a={name:"hands-on/003-boot-long-mode-3.md"};function n(r,e,l,c,s,i){return p(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="_003-3-模式切换-从保护模式到-long-mode-的五步状态机" tabindex="-1">003-3 模式切换：从保护模式到 Long Mode 的五步状态机 <a class="header-anchor" href="#_003-3-模式切换-从保护模式到-long-mode-的五步状态机" aria-label="Permalink to &quot;003-3 模式切换：从保护模式到 Long Mode 的五步状态机&quot;">​</a></h1><blockquote><p>标签：x86_64, EFER, CR0/CR3/CR4, 远跳转, 64 位 GDT, 状态机切换 前置：<a href="./003-boot-long-mode-2">003-2 页表构建</a></p></blockquote><h2 id="本篇目标" tabindex="-1">本篇目标 <a class="header-anchor" href="#本篇目标" aria-label="Permalink to &quot;本篇目标&quot;">​</a></h2><p>上一篇我们把页表搭好了——</p><p>PML4 在 0x1000、PDPT 在 0x2000、PD 在 0x3000，</p><p>用 2MB 大页恒等映射了前 8MB 物理内存，还建立了 Higher-Half Kernel 映射。</p><p>本篇的核心任务是实现 <code>enter_long_mode</code> 函数和 <code>long_mode_entry</code> 入口点，</p><p>把 CPU 从保护模式带入 64 位 Long Mode。</p><p>这五个步骤必须按固定顺序执行，</p><p>任何一步跳过、调换或者参数写错，CPU 就直接三重故障。</p><p>没有报错信息，没有错误码，QEMU 窗口闪一下就没了。</p><h2 id="模式切换五步走" tabindex="-1">模式切换五步走 <a class="header-anchor" href="#模式切换五步走" aria-label="Permalink to &quot;模式切换五步走&quot;">​</a></h2><h3 id="step-1-实现-enter-long-mode——第一步-加载-cr3" tabindex="-1">Step 1: 实现 enter_long_mode——第一步：加载 CR3 <a class="header-anchor" href="#step-1-实现-enter-long-mode——第一步-加载-cr3" aria-label="Permalink to &quot;Step 1: 实现 enter_long_mode——第一步：加载 CR3&quot;">​</a></h3><p><strong>目标</strong>：</p><p>在 <code>enter_long_mode</code> 函数的开头，把 PML4 的物理地址（0x1000）写入 CR3 寄存器。</p><p><strong>设计思路</strong>：</p><p>CR3 寄存器存储当前页表的 PML4 表物理基地址。</p><p>把 0x1000 写入 CR3，CPU 就知道页表从哪开始查了。</p><p>这一步必须在开启分页（CR0.PG）之前完成——</p><p>道理很简单：分页开启后 CPU 立即开始用页表翻译地址，</p><p>如果 CR3 还没有指向合法的 PML4 表，</p><p>CPU 会去一个不确定的位置查表，大概率读到垃圾数据然后三重故障。</p><p>写 CR3 的副作用是使 TLB（Translation Lookaside Buffer，页表缓存）中所有非全局页的条目失效，</p><p>不过此时分页还没开启，TLB 里本来就没有有效条目，所以这个副作用无所谓。</p><p><strong>实现约束</strong>：</p><p>用 <code>movl</code> 把立即数 0x1000 加载到 EAX，再把 EAX 写入 CR3。</p><p>CR3 不能直接接受立即数写入，必须通过通用寄存器中转。</p><p><strong>验证</strong>：</p><p>GDB 中在 CR3 写入后设断点，用 <code>info registers cr3</code> 查看，应该显示 0x1000。</p><h3 id="step-2-第二步-启用-pae" tabindex="-1">Step 2: 第二步：启用 PAE <a class="header-anchor" href="#step-2-第二步-启用-pae" aria-label="Permalink to &quot;Step 2: 第二步：启用 PAE&quot;">​</a></h3><p><strong>目标</strong>：</p><p>设置 CR4 的 bit 5（PAE，Physical Address Extension），让 CPU 支持四级页表结构。</p><p><strong>设计思路</strong>：</p><p>CR4.PAE（bit 5，值 0x20）启用物理地址扩展，</p><p>让 CPU 支持 36 位以上的物理地址和四级页表结构。</p><p>Long Mode 强制要求 PAE——</p><p>没有 PAE 就无法使用 PML4→PDPT→PD→PT 的四级结构，</p><p>没有四级结构就无法进入 Long Mode。</p><p>Intel SDM Vol.3A §10.8.5 明确要求 PAE 必须在 EFER.LME 之前启用，这是状态机的硬性约束。</p><p><strong>实现约束</strong>：</p><p>CR4 不能直接做位运算（<code>orl $0x20, %cr4</code> 是非法指令），</p><p>必须通过通用寄存器中转：</p><p>先 <code>movl %cr4, %eax</code> 读出来、用 <code>orl $CR4_PAE, %eax</code> 设置 bit 5、</p><p>再 <code>movl %eax, %cr4</code> 写回去。</p><p>这和上一章中 CR0 的操作方式一样，是 x86 ISA 的架构限制。</p><p><strong>验证</strong>：</p><p>GDB 中用 <code>info registers cr4</code> 查看，应该包含 0x20（PAE 位）。</p><h3 id="step-3-第三步-设置-efer-lme——最危险的一步" tabindex="-1">Step 3: 第三步：设置 EFER.LME——最危险的一步 <a class="header-anchor" href="#step-3-第三步-设置-efer-lme——最危险的一步" aria-label="Permalink to &quot;Step 3: 第三步：设置 EFER.LME——最危险的一步&quot;">​</a></h3><p><strong>目标</strong>：</p><p>通过 MSR 0xC0000080（EFER 寄存器）设置 LME 位（bit 8，值 0x100），</p><p>告诉 CPU &quot;我要进入 Long Mode&quot;。</p><p><strong>设计思路</strong>：</p><p>EFER（Extended Feature Enable Register）是一个 MSR（Model-Specific Register），地址 0xC0000080。</p><p><code>rdmsr</code> 把 ECX 指定的 MSR 读入 EDX:EAX（高 32 位在 EDX，低 32 位在 EAX），</p><p>我们用 OR 指令设置 EAX 中的 bit 8（LME），然后 <code>wrmsr</code> 写回去。</p><p>EDX 在整个过程中保持不变——我们不需要修改 EFER 的高 32 位。</p><p><strong>踩坑预警</strong>：</p><p>这一步是整个 Long Mode 切换中最容易出错的地方，也是我们踩过最大坑的地方。</p><p>我们在开发时把 EFER_LME 定义成了 0x1000 而不是 0x100。</p><p>0x1000 是 bit 12，对应 AMD 的 SVME 位。</p><p><code>wrmsr</code> 不会报错——CPU 很乖地设置了 bit 12 而不是 bit 8。</p><p>然后继续执行后续步骤、开启分页——</p><p>CPU 在 CR0.PG 从 0 变成 1 的瞬间检查 EFER.LME 是否为 1，</p><p>发现 LME=0 但 PG=1，直接 #GP 然后三重故障。</p><p>GDB 里的线索是 EFER=0x1000，只有 SVME 没有 LME。</p><p>一个十六进制位的差距，CPU 不报错、汇编不报错、链接不报错，运行时直接炸。</p><p><strong>验证</strong>：</p><p>GDB 中用 <code>info registers efer</code> 查看，应该包含 0x100（LME 位）。</p><p>如果看到 0x1000 而没有 0x100，那就是常量定义写错了。</p><h3 id="step-4-第四步-加载扩展-gdt" tabindex="-1">Step 4: 第四步：加载扩展 GDT <a class="header-anchor" href="#step-4-第四步-加载扩展-gdt" aria-label="Permalink to &quot;Step 4: 第四步：加载扩展 GDT&quot;">​</a></h3><p><strong>目标</strong>：</p><p>用 <code>lgdt</code> 加载包含 64 位描述符的扩展 GDT。</p><p><strong>设计思路</strong>：</p><p>在远跳转之前必须加载包含 64 位描述符的 GDT。</p><p>因为接下来的 <code>ljmp $0x18, ...</code> 需要用选择子 0x18 去 GDT 查找描述符——</p><p>如果此时 GDTR 还指向旧的 3 条目 GDT（null、32 位代码、32 位数据），</p><p>偏移 0x18 处什么都没有，CPU 查到一个 null 描述符，直接 #GP。</p><p><code>gdt64_ptr</code> 是新的 64 位 GDT 指针，</p><p>格式是 2 字节 Limit + 4 字节低地址 + 4 字节高地址（全零）。</p><p><strong>实现约束</strong>：</p><p>GDT 指针用 <code>.long</code> + <code>.long</code> 而不是 <code>.quad</code>——</p><p>因为在 32 位 ELF（elf32-i386）里使用 <code>.quad</code> 存储 GDT 地址会触发链接器的 64 位重定位错误。</p><p>拆成两个 <code>.long</code> 之后，</p><p>低 32 位生成普通的 R_386_32 重定位，高 32 位是常量 0 不需要重定位。</p><p>GDT 本身在 stage2.S 的 <code>.gdt</code> section 中定义，包含 5 个描述符：</p><ul><li>null（0x00）</li><li>32 位代码段（0x08）</li><li>32 位数据段（0x10）</li><li>64 位代码段（0x18）</li><li>64 位数据段（0x20）</li></ul><p>64 位代码段描述符的值是 0x00AF9A000000FFFF——</p><p>L=1 且 D=0 是让 CPU 进入真正 64 位模式的关键组合。</p><p><strong>踩坑预警</strong>：</p><p>如果用了 32 位版的 <code>gdt_ptr</code> 而不是 64 位版的 <code>gdt64_ptr</code>，</p><p>GDT 里没有偏移 0x18 处的 64 位描述符，远跳转时 CPU 查到 null 描述符直接 #GP。</p><p>另外 64 位代码段的 L 位必须为 1、D 位必须为 0——</p><p>如果 L=0，即使 EFER.LME=1、CR0.PG=1，CPU 也只在兼容模式下运行；</p><p>如果 D=1 且 L=1，这是保留组合，行为未定义。</p><p><strong>验证</strong>：</p><p>用 <code>objdump -s -j .gdt build/boot/stage2</code> 查看 GDT section 的原始字节，</p><p>确认偏移 0x18 处有 64 位代码段描述符。</p><h3 id="step-5-第五步-开启分页-远跳转" tabindex="-1">Step 5: 第五步：开启分页 + 远跳转 <a class="header-anchor" href="#step-5-第五步-开启分页-远跳转" aria-label="Permalink to &quot;Step 5: 第五步：开启分页 + 远跳转&quot;">​</a></h3><p><strong>目标</strong>：</p><p>设置 CR0.PG（bit 31）开启分页，然后执行 <code>ljmp $0x18, $long_mode_entry</code> 远跳转到 64 位代码。</p><p><strong>设计思路</strong>：</p><p>CR0.PG 从 0 变成 1 的瞬间是整个状态机的&quot;激活点&quot;。</p><p>CPU 检查 CR4.PAE=1、EFER.LME=1、CR3 指向合法 PML4 表——</p><p>全部满足后，CPU 自动设置 EFER.LMA（Long Mode Active，bit 10），分页正式生效。</p><p>由于我们的页表做的是恒等映射，</p><p>当前正在执行的代码的物理地址恰好同时是有效的虚拟地址和物理地址，CPU 能继续取到正确的指令。</p><p>分页生效后 CPU 进入 Compatibility Mode，</p><p>然后 <code>ljmp $0x18, $long_mode_entry</code> 远跳转刷新 CS，让 CPU 真正进入 64 位模式。</p><p><strong>实现约束</strong>：</p><p>CR0 的写入值是 0x80000001，同时设置 PG 和 PE——</p><p>OR 操作不会清除已有的位，所以 PE 保持为 1。</p><p>选择子 0x18 的拆解是：</p><p>Index = 0x18 &gt;&gt; 3 = 3（GDT 第 4 个条目），TI = 0（使用 GDT），RPL = 0（Ring 0）。</p><p>远跳转之后的代码永远不会执行——<code>ljmp</code> 不返回。</p><p><strong>踩坑预警</strong>：</p><p>这五步的顺序不可调换。</p><p>尤其是 PAE 必须在 LME 之前设置，LME 必须在 PG 之前设置。</p><p>如果反过来——比如先开 PG 再开 LME——</p><p>CPU 会因为你试图在没有 Long Mode 的情况下启用分页而直接 #GP。</p><p><strong>验证</strong>：</p><p>GDB 中开启分页后查看 CR0 = 0x80000011（PE+PG），CR4 = 0x20（PAE），</p><p>EFER 包含 LME（0x100）和 LMA（0x400）。</p><h2 id="_64-位入口点初始化" tabindex="-1">64 位入口点初始化 <a class="header-anchor" href="#_64-位入口点初始化" aria-label="Permalink to &quot;64 位入口点初始化&quot;">​</a></h2><h3 id="step-6-实现-long-mode-entry" tabindex="-1">Step 6: 实现 long_mode_entry <a class="header-anchor" href="#step-6-实现-long-mode-entry" aria-label="Permalink to &quot;Step 6: 实现 long_mode_entry&quot;">​</a></h3><p><strong>目标</strong>：</p><p>在 stage2.S 中添加 <code>.code64</code> 段的 <code>long_mode_entry</code> 入口点，完成 64 位环境初始化。</p><p><strong>设计思路</strong>：</p><p>远跳转执行后，CPU 进入 64 位模式，</p><p>CS 已经刷新为 64 位代码段选择子（0x18），</p><p>但 DS、ES、FS、GS、SS 这些数据段寄存器还残留着保护模式的旧值。</p><p>我们需要把它们全部重载为 64 位数据段选择子（0x20）。</p><p>接着用 <code>movabsq</code> 指令把一个 64 位立即数（0x90000）加载到 RSP 设置 64 位栈指针。</p><p>最后输出字符 <code>L</code>（0x4C）到 debugcon 端口 0xE9 作为验证。</p><p><strong>实现约束</strong>：</p><p><code>long_mode_entry</code> 需要声明为 <code>.global</code>，</p><p>因为 <code>enter_long_mode</code> 中的 <code>ljmp</code> 需要引用这个符号。</p><p><code>.code64</code> 指令必须紧贴在 <code>long_mode_entry</code> 标签之前，</p><p>确保从这里开始生成 64 位指令编码。</p><p><code>movabsq</code> 是 GAS 中加载 64 位立即数到寄存器的助记符，不是 <code>movq</code>——</p><p><code>movq</code> 只能接受 32 位符号扩展立即数。</p><p><strong>验证</strong>：</p><p>构建并运行 QEMU，检查 <code>debug.log</code> 文件内容。</p><p>如果里面同时出现 <code>P</code>（保护模式）和 <code>L</code>（Long Mode），</p><p>说明整个启动链条全部正确。</p><h2 id="修改-stage2-调用链" tabindex="-1">修改 stage2 调用链 <a class="header-anchor" href="#修改-stage2-调用链" aria-label="Permalink to &quot;修改 stage2 调用链&quot;">​</a></h2><p>在 stage2.S 的 <code>pm_entry</code>（保护模式入口点）中，输出 <code>P</code> 之后，需要调用新的两个函数。</p><p>调用顺序是先 <code>setup_page_tables</code> 再 <code>enter_long_mode</code>——</p><p>因为 <code>enter_long_mode</code> 内部会把 CR3 指向页表，所以页表必须提前建好。</p><p><code>enter_long_mode</code> 不会返回（最后是一条 <code>ljmp</code> 跳走了），</p><p>所以它后面的 <code>cli; hlt</code> 只是保护性代码。</p><p>同时需要在 <code>boot/CMakeLists.txt</code> 中把 <code>boot_longmode</code> 目标的对象文件链接进 stage2——</p><p>在 <code>add_executable(stage2 ...)</code> 中追加 <code>$&lt;TARGET_OBJECTS:boot_longmode&gt;</code>。</p><p>用以下命令验证调用链的正确性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>objdump -d build/boot/stage2 | grep -A5 pm_entry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>确认 pm_entry 之后有 <code>call setup_page_tables</code> 和 <code>call enter_long_mode</code>。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>构建命令和之前一样，在项目根目录执行 CMake 构建。</p><p>运行后检查 <code>debug.log</code> 文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cat debug.log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>预期输出是两个字符：先 <code>P</code>（保护模式切换成功，来自 tag 002），</p><p>然后 <code>L</code>（Long Mode 切换成功）。</p><p>如果什么都没有或者 QEMU 反复重启，说明切换过程中某一步出了问题。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p>在 GDB 中连接 QEMU（<code>target remote :1234</code>），</p><p>加载 ELF 文件（<code>file build/boot/stage2</code>），</p><p>在 <code>enter_long_mode</code> 的关键步骤之间设置断点，</p><p>逐步查看 CR0、CR4、EFER 的变化。</p><p>开启分页后的正确状态应该是 CR0 = 0x80000011（PE+PG），CR4 = 0x20（PAE），</p><p>EFER 包含 LME（0x100）和 LMA（0x400）。</p><p>如果遇到三重故障，用 <code>qemu-system-x86_64 -d int -no-reboot ...</code> 启动，</p><p>QEMU 会在每次异常时打印信息。</p><p>CS=0x0008 说明还在保护模式，异常发生在 <code>enter_long_mode</code> 内部；</p><p>CS=0x0018 说明已经进入 Long Mode 但后续出了问题。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>到这里 tag 003 的全部内容就完成了。</p><p>从保护模式到 Long Mode 的切换，核心就是五步状态机：</p><p>CR3 加载页表基址、CR4.PAE 启用物理地址扩展、EFER.LME 开启 Long Mode 使能、</p><p>lgdt 加载扩展 GDT、CR0.PG 开启分页 + ljmp 远跳转。</p><p>每一步都有严格的前置条件和顺序约束，任何一步出错都会导致三重故障。</p><p>验证方式很简单：构建并运行 QEMU，检查 <code>debug.log</code> 文件出现 <code>L</code> 字符。</p><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>Long Mode 状态机</td><td>CR3 → PAE → LME → LGDT → PG → ljmp，严格有序</td></tr><tr><td>EFER.LME</td><td>MSR 0xC0000080 bit 8，值 0x100，不是 0x1000</td></tr><tr><td>64 位 GDT 描述符</td><td>L=1, D=0，代码段值 0x00AF9A000000FFFF</td></tr><tr><td>远跳转选择子</td><td>0x18（64 位代码段），触发真正 64 位模式</td></tr><tr><td>GDT64 指针</td><td>.long + .long 拼接 64 位基地址，避免 .quad 重定位</td></tr><tr><td>验证输出</td><td><code>outb &#39;L&#39;</code> 到 debugcon 0xE9，debug.log 应出现 <code>L</code></td></tr></tbody></table><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol.3A §10.8.5 — Initializing IA-32e Mode：五步切换序列</li><li>Intel SDM Vol.3A §10.8.5.3 — CS.L 和 CS.D 决定子模式：L=1/D=0 进入 64 位模式</li><li>Intel SDM Vol.3A §2.5 — Control Registers：CR0.PG/PE、CR3、CR4.PAE 位定义</li><li>Intel SDM Vol.3A §3.4.5 — Segment Descriptors：L 位和 D 位的含义</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Setting_Up_Long_Mode" target="_blank" rel="noreferrer">Setting Up Long Mode</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Global_Descriptor_Table" target="_blank" rel="noreferrer">Global Descriptor Table</a></li></ul>',183)])])}const b=o(a,[["render",n]]);export{h as __pageData,b as default};
